import React from "react"
import BusinessRegistrationFlow from "./BusinessRegistrationFlow"
import LayoutCommon from "src/components/Common/LayoutCommon"

const BusinessRegistrationPage = () => {
  const handleClose = () => {
    window.history.back()
  }

  return (
    <LayoutCommon>
      <div className="business-registration-page">
        <div className="page-background">
          <BusinessRegistrationFlow onClose={handleClose} />
        </div>
      </div>
    </LayoutCommon>
  )
}

export default BusinessRegistrationPage

