import { SearchOutlined } from "@ant-design/icons"
import { Button, Col, DatePicker, Form, Input, Row, Select } from "antd"
import { useEffect, useState } from "react"
import { useNavigate } from "react-router-dom"
import ButtonCustom from "src/components/MyButton/Button"
import RegionService from "src/services/RegionService"
import "./BusinessRegistration.scss"
import ImageUploadPreview from "./ImageUploadPreview"

const { Option } = Select

const RegistrationFormStep = ({ initialData = {}, onSubmit, onCancel }) => {
  const [form] = Form.useForm()
  const [previewCCCD, setPreviewCCCD] = useState(null)
  const [previewAvatar, setPreviewAvatar] = useState(null)
  const [previewPortrait, setPreviewPortrait] = useState(null)
  const navigate = useNavigate()

  const [provinces, setProvinces] = useState([])
  const [districts, setDistricts] = useState([])
  const [wards, setWards] = useState([])

  const [selectedProvinceId, setSelectedProvinceId] = useState(null)
  const [selectedDistrictId, setSelectedDistrictId] = useState(null)
  const [selectedWardId, setSelectedWardId] = useState(null)

  const [repProvinces, setRepProvinces] = useState([])
  const [repDistricts, setRepDistricts] = useState([])
  const [repWards, setRepWards] = useState([])

  const [selectedRepProvinceId, setSelectedRepProvinceId] = useState(null)
  const [selectedRepDistrictId, setSelectedRepDistrictId] = useState(null)
  const [selectedRepWardId, setSelectedRepWardId] = useState(null)

  useEffect(() => {
    const fetchProvinces = async () => {
      try {
        const response = await RegionService.getLocationVN({ RegionId: 234 })
        if (response?.Object) {
          setProvinces(response?.Object)
          setRepProvinces(response?.Object)
        }
      } catch (error) {
        console.error("Lỗi khi lấy danh sách Tỉnh/Thành phố:", error)
      }
    }
    fetchProvinces()
  }, [])

  useEffect(() => {
    if (selectedProvinceId) {
      const fetchDistricts = async () => {
        try {
          const response = await RegionService.getAllChidrenByRegionId({
            RegionId: selectedProvinceId,
          })
          if (response?.Object) {
            setDistricts(response?.Object)
            setWards([])
            form.setFieldsValue({ district: null, ward: null })
            setSelectedDistrictId(null)
            setSelectedWardId(null)
          }
        } catch (error) {
          console.error("Lỗi khi lấy danh sách Quận/Huyện:", error)
        }
      }
      fetchDistricts()
    }
  }, [selectedProvinceId, form])

  useEffect(() => {
    if (selectedDistrictId) {
      const fetchWards = async () => {
        try {
          const response = await RegionService.getByRegionId({
            regionId: selectedDistrictId,
          })
          if (response?.Object) {
            setWards(response?.Object)
            form.setFieldsValue({ ward: null })
            setSelectedWardId(null)
          }
        } catch (error) {
          console.error("Lỗi khi lấy danh sách Phường/Xã:", error)
        }
      }
      fetchWards()
    }
  }, [selectedDistrictId, form])

  useEffect(() => {
    const provinceName =
      provinces.find(p => p.RegionID === selectedProvinceId)?.RegionName || ""
    const districtName =
      districts.find(d => d.RegionID === selectedDistrictId)?.RegionName || ""
    const wardName =
      wards.find(w => w.RegionID === selectedWardId)?.RegionName || ""

    let fullAddressPart = ""
    if (wardName) fullAddressPart += wardName
    if (districtName)
      fullAddressPart += (fullAddressPart ? ", " : "") + districtName
    if (provinceName)
      fullAddressPart += (fullAddressPart ? ", " : "") + provinceName

    form.setFieldsValue({ fullAddressLocation: fullAddressPart })
  }, [
    selectedProvinceId,
    selectedDistrictId,
    selectedWardId,
    provinces,
    districts,
    wards,
    form,
  ])

  useEffect(() => {
    if (selectedRepProvinceId) {
      const fetchRepDistricts = async () => {
        try {
          const response = await RegionService.getAllChidrenByRegionId({
            RegionId: selectedRepProvinceId,
          })
          if (response?.Object) {
            setRepDistricts(response?.Object)
            setRepWards([])
            form.setFieldsValue({ repDistrict: null, repWard: null })
            setSelectedRepDistrictId(null)
            setSelectedRepWardId(null)
          }
        } catch (error) {
          console.error("Lỗi khi lấy danh sách Quận/Huyện (Đại diện):", error)
        }
      }
      fetchRepDistricts()
    }
  }, [selectedRepProvinceId, form])

  useEffect(() => {
    if (selectedRepDistrictId) {
      const fetchRepWards = async () => {
        try {
          const response = await RegionService.getByRegionId({
            regionId: selectedRepDistrictId,
          })
          if (response?.Object) {
            setRepWards(response?.Object)
            form.setFieldsValue({ repWard: null })
            setSelectedRepWardId(null)
          }
        } catch (error) {
          console.error("Lỗi khi lấy danh sách Phường/Xã (Đại diện):", error)
        }
      }
      fetchRepWards()
    }
  }, [selectedRepDistrictId, form])

  useEffect(() => {
    const repProvinceName =
      repProvinces.find(p => p.RegionID === selectedRepProvinceId)
        ?.RegionName || ""
    const repDistrictName =
      repDistricts.find(d => d.RegionID === selectedRepDistrictId)
        ?.RegionName || ""
    const repWardName =
      repWards.find(w => w.RegionID === selectedRepWardId)?.RegionName || ""

    let fullRepAddressPart = ""
    if (repWardName) fullRepAddressPart += repWardName
    if (repDistrictName)
      fullRepAddressPart += (fullRepAddressPart ? ", " : "") + repDistrictName
    if (repProvinceName)
      fullRepAddressPart += (fullRepAddressPart ? ", " : "") + repProvinceName

    form.setFieldsValue({ fullRepAddressLocation: fullRepAddressPart })
  }, [
    selectedRepProvinceId,
    selectedRepDistrictId,
    selectedRepWardId,
    repProvinces,
    repDistricts,
    repWards,
    form,
  ])

  const handleBack = () => {
    if (onCancel) onCancel()
    else navigate(-1)
  }

  const handleCCCDScanSuccess = async scannedData => {
    form.setFieldsValue({
      RepresentativeName: scannedData.FullName,

      // TaxIssuedDate: scannedData.IdentificationIssueDate
      //   ? dayjs(scannedData.IdentificationIssueDate)
      //   : null,
      repStreetAddress: scannedData.Address,
    })

    const fullScannedAddress = scannedData.Address
    const parts = fullScannedAddress.split(", ").map(part => part.trim())

    let foundRepProvinceId = null
    let foundRepDistrictId = null
    let foundRepWardId = null

    for (const part of parts) {
      const matchingWard = repWards.find(w => w.RegionName === part)
      if (matchingWard) {
        foundRepWardId = matchingWard.RegionID
        break
      }
      const matchingDistrict = repDistricts.find(d => d.RegionName === part)
      if (matchingDistrict) {
        foundRepDistrictId = matchingDistrict.RegionID
        break
      }
      const matchingProvince = repProvinces.find(p => p.RegionName === part)
      if (matchingProvince) {
        foundRepProvinceId = matchingProvince.RegionID
        break
      }
    }

    if (foundRepProvinceId) {
      form.setFieldsValue({ repProvince: foundRepProvinceId })
      setSelectedRepProvinceId(foundRepProvinceId)
    }
    if (foundRepDistrictId) {
      form.setFieldsValue({ repDistrict: foundRepDistrictId })
      setSelectedRepDistrictId(foundRepDistrictId)
    }
    if (foundRepWardId) {
      form.setFieldsValue({ repWard: foundRepWardId })
      setSelectedRepWardId(foundRepWardId)
    }
  }

  const handleSubmit = values => {
    const CCCDImage = form.getFieldValue("CCCDImage")
    const Avatar = form.getFieldValue("Avatar")
    const Portrait = form.getFieldValue("Portrait")

    const streetAddress = values.StreetAddress || ""
    const fullAddressLocation = form.getFieldValue("fullAddressLocation") || ""
    const finalBusinessAddress =
      streetAddress +
      (streetAddress && fullAddressLocation ? ", " : "") +
      fullAddressLocation

    const repStreetAddress = values.repStreetAddress || ""
    const fullRepAddressLocation =
      form.getFieldValue("fullRepAddressLocation") || ""
    const finalRepresentativeAddress =
      repStreetAddress +
      (repStreetAddress && fullRepAddressLocation ? ", " : "") +
      fullRepAddressLocation

    const allData = {
      ...initialData,
      ...values,
      CCCDImage,
      Avatar,
      Portrait,
      TaxIssuedDate: values.TaxIssuedDate
        ? values.TaxIssuedDate.toISOString()
        : null,
      BusinessAddress: finalBusinessAddress,
      BusinessProvinceId: selectedProvinceId,
      BusinessDistrictId: selectedDistrictId,
      BusinessWardId: selectedWardId,

      RepresentativeAddress: finalRepresentativeAddress,
      RepresentativeProvinceId: selectedRepProvinceId,
      RepresentativeDistrictId: selectedRepDistrictId,
      RepresentativeWardId: selectedRepWardId,
    }

    onSubmit(allData)
  }

  return (
    <div className="step-content">
      <h2 className="step-title">Đăng kí Hội Viên Doanh Nghiệp</h2>

      <Form
        form={form}
        layout="vertical"
        initialValues={initialData}
        onFinish={handleSubmit}
        className="registration-form"
      >
        <Row gutter={16}>
          <Col span={12}>
            <Form.Item
              name="CCCDImage"
              label="Ảnh đăng ký kinh doanh:"
              rules={[
                {
                  required: true,
                  message: "Vui lòng chọn ảnh đăng ký kinh doanh",
                },
              ]}
            >
              <ImageUploadPreview
                previewImage={previewCCCD}
                setPreviewImage={setPreviewCCCD}
                fieldName="CCCDImage"
                form={form}
                label="Ảnh đăng ký kinh doanh"
                onScanSuccess={handleCCCDScanSuccess}
              />
            </Form.Item>
          </Col>

          <Col span={12}>
            <Form.Item
              name="Avatar"
              label="Ảnh doanh nghiệp:"
              rules={[
                { required: true, message: "Vui lòng chọn ảnh doanh nghiệp" },
              ]}
            >
              <ImageUploadPreview
                previewImage={previewAvatar}
                setPreviewImage={setPreviewAvatar}
                fieldName="Avatar"
                form={form}
                label="Ảnh doanh nghiệp"
              />
            </Form.Item>
          </Col>
        </Row>
        <Row gutter={16}>
          <Col span={12}>
            <Form.Item
              name="OrganizationName"
              label="Tên Doanh Nghiệp"
              rules={[
                {
                  required: true,
                  message: "Vui lòng nhập tên doanh nghiệp",
                },
              ]}
            >
              <Input />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item name="TaxCode" label="Số giấy phép kinh doanh/MST">
              <Input
                placeholder="Nhập MST để tìm kiếm"
                suffix={
                  <SearchOutlined
                    style={{ color: "#1890ff", cursor: "pointer" }}
                  />
                }
              />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item
              name="PhoneNumber"
              label="Số Điện Thoại Doanh Nghiệp"
              rules={[
                { required: true, message: "Vui lòng nhập số điện thoại" },
                {
                  pattern: /^\d{10}$/,
                  message: "Số điện thoại không hợp lệ",
                },
              ]}
            >
              <Input />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item
              name="TaxIssuedDate"
              label="Ngày cấp giấy phép kinh doanh/MST"
              rules={[{ required: true, message: "Vui lòng chọn ngày cấp" }]}
            >
              <DatePicker
                style={{ width: "100%", height: "40px" }}
                format="DD/MM/YYYY"
                placeholder="Chọn ngày cấp"
              />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item
              name="Email"
              label="Email doanh nghiệp"
              rules={[
                { required: true, message: "Vui lòng nhập email" },
                { type: "email", message: "Email không hợp lệ" },
              ]}
            >
              <Input />
            </Form.Item>
          </Col>
        </Row>

        <Row gutter={16}>
          <Col span={8}>
            <Form.Item
              name="province"
              label="Tỉnh/Thành phố"
              rules={[
                { required: true, message: "Vui lòng chọn Tỉnh/Thành phố" },
              ]}
            >
              <Select
                placeholder="Chọn Tỉnh/Thành phố"
                showSearch
                optionFilterProp="children"
                onChange={value => setSelectedProvinceId(value)}
                filterOption={(input, option) =>
                  (option?.children ?? "")
                    .toLowerCase()
                    .includes(input.toLowerCase())
                }
              >
                {provinces.map(province => (
                  <Option key={province.RegionID} value={province.RegionID}>
                    {province.RegionName}
                  </Option>
                ))}
              </Select>
            </Form.Item>
          </Col>
          <Col span={8}>
            <Form.Item
              name="district"
              label="Quận/Huyện"
              rules={[{ required: true, message: "Vui lòng chọn Quận/Huyện" }]}
            >
              <Select
                placeholder="Chọn Quận/Huyện"
                showSearch
                optionFilterProp="children"
                onChange={value => setSelectedDistrictId(value)}
                filterOption={(input, option) =>
                  (option?.children ?? "")
                    .toLowerCase()
                    .includes(input.toLowerCase())
                }
                disabled={!selectedProvinceId}
              >
                {districts.map(district => (
                  <Option key={district.RegionID} value={district.RegionID}>
                    {district.RegionName}
                  </Option>
                ))}
              </Select>
            </Form.Item>
          </Col>
          <Col span={8}>
            <Form.Item
              name="ward"
              label="Phường/Xã"
              rules={[{ required: true, message: "Vui lòng chọn Phường/Xã" }]}
            >
              <Select
                placeholder="Chọn Phường/Xã"
                showSearch
                optionFilterProp="children"
                onChange={value => setSelectedWardId(value)}
                filterOption={(input, option) =>
                  (option?.children ?? "")
                    .toLowerCase()
                    .includes(input.toLowerCase())
                }
                disabled={!selectedDistrictId}
              >
                {wards.map(ward => (
                  <Option key={ward.RegionID} value={ward.RegionID}>
                    {ward.RegionName}
                  </Option>
                ))}
              </Select>
            </Form.Item>
          </Col>
        </Row>
        <Form.Item
          name="StreetAddress"
          label="Số nhà, tên đường, thôn, xóm..."
          rules={[
            { required: true, message: "Vui lòng nhập địa chỉ chi tiết" },
          ]}
        >
          <Input />
        </Form.Item>
        <Form.Item name="fullAddressLocation" hidden>
          <Input />
        </Form.Item>

        <br />
        <Row gutter={16}>
          <Col span={12}>
            <Form.Item
              name="Portrait"
              label="Ảnh chân dung người đại diện:"
              rules={[
                { required: true, message: "Vui lòng chọn ảnh chân dung" },
              ]}
            >
              <ImageUploadPreview
                previewImage={previewPortrait}
                setPreviewImage={setPreviewPortrait}
                fieldName="Portrait"
                form={form}
                label="Ảnh chân dung người đại diện"
              />
            </Form.Item>
          </Col>
        </Row>
        <Row gutter={16}>
          <Col span={12}>
            <Form.Item
              name="RepresentativeName"
              label="Tên Người Đại Diện"
              rules={[
                {
                  required: true,
                  message: "Vui lòng nhập tên người đại diện",
                },
              ]}
            >
              <Input />
            </Form.Item>
          </Col>

          <Col span={12}>
            <Form.Item
              name="RepresentativePhoneNumber"
              label="Số Điện Thoại người đại diện"
              rules={[
                { required: true, message: "Vui lòng nhập số điện thoại" },
                {
                  pattern: /^\d{10}$/,
                  message: "Số điện thoại không hợp lệ",
                },
              ]}
            >
              <Input />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item
              name="AccountName"
              label="Đơn vị"
              rules={[{ required: true, message: "Vui lòng nhập đơn vị" }]}
            >
              <Input />
            </Form.Item>
          </Col>
        </Row>

        <Row gutter={16}>
          <Col span={8}>
            <Form.Item
              name="repProvince"
              label="Tỉnh/Thành phố"
              rules={[
                { required: true, message: "Vui lòng chọn Tỉnh/Thành phố" },
              ]}
            >
              <Select
                placeholder="Chọn Tỉnh/Thành phố"
                showSearch
                optionFilterProp="children"
                onChange={value => setSelectedRepProvinceId(value)}
                filterOption={(input, option) =>
                  (option?.children ?? "")
                    .toLowerCase()
                    .includes(input.toLowerCase())
                }
              >
                {repProvinces.map(province => (
                  <Option key={province.RegionID} value={province.RegionID}>
                    {province.RegionName}
                  </Option>
                ))}
              </Select>
            </Form.Item>
          </Col>
          <Col span={8}>
            <Form.Item
              name="repDistrict"
              label="Quận/Huyện"
              rules={[{ required: true, message: "Vui lòng chọn Quận/Huyện" }]}
            >
              <Select
                placeholder="Chọn Quận/Huyện"
                showSearch
                optionFilterProp="children"
                onChange={value => setSelectedRepDistrictId(value)}
                filterOption={(input, option) =>
                  (option?.children ?? "")
                    .toLowerCase()
                    .includes(input.toLowerCase())
                }
                disabled={!selectedRepProvinceId}
              >
                {repDistricts.map(district => (
                  <Option key={district.RegionID} value={district.RegionID}>
                    {district.RegionName}
                  </Option>
                ))}
              </Select>
            </Form.Item>
          </Col>
          <Col span={8}>
            <Form.Item
              name="repWard"
              label="Phường/Xã"
              rules={[{ required: true, message: "Vui lòng chọn Phường/Xã" }]}
            >
              <Select
                placeholder="Chọn Phường/Xã"
                showSearch
                optionFilterProp="children"
                onChange={value => setSelectedRepWardId(value)}
                filterOption={(input, option) =>
                  (option?.children ?? "")
                    .toLowerCase()
                    .includes(input.toLowerCase())
                }
                disabled={!selectedRepDistrictId}
              >
                {repWards.map(ward => (
                  <Option key={ward.RegionID} value={ward.RegionID}>
                    {ward.RegionName}
                  </Option>
                ))}
              </Select>
            </Form.Item>
          </Col>
        </Row>
        <Form.Item
          name="repStreetAddress"
          label="Số nhà, tên đường, thôn, xóm..."
          rules={[
            { required: true, message: "Vui lòng nhập địa chỉ chi tiết" },
          ]}
        >
          <Input />
        </Form.Item>
        <Form.Item name="fullRepAddressLocation" hidden>
          <Input />
        </Form.Item>

        <Form.Item name="Description" label="Mô Tả">
          <Input.TextArea
            className="custom-textarea"
            style={{
              minHeight: "80px",
              height: "300px",
              overflow: "hidden auto",
            }}
          />
        </Form.Item>

        <Form.Item className="step-actions">
          <div className="button-group-step">
            <div>
              <ButtonCustom onClick={handleBack}>Quay lại</ButtonCustom>
            </div>
            <div>
              <Button type="primary" htmlType="submit">
                Gửi đơn
              </Button>
            </div>
          </div>
        </Form.Item>
      </Form>
    </div>
  )
}

export default RegistrationFormStep
