import React from "react"
import { Upload, message } from "antd" // Import message for notifications
import { CloseCircleOutlined } from "@ant-design/icons"
import "./BusinessRegistration.scss"
import AuthService from "src/services/AuthService" // Import AuthService

const ImageUploadPreview = ({
  previewImage,
  setPreviewImage,
  fieldName,
  form,
  label,
  onScanSuccess, // New prop for scan success callback
}) => {
  const beforeUpload = async file => {
    const reader = new FileReader()
    reader.onloadend = () => {
      setPreviewImage(reader.result)
      form.setFieldsValue({ [fieldName]: file })
    }
    reader.readAsDataURL(file)

    // If the uploaded image is for CCCD, call the scan API
    if (fieldName === "CCCDImage") {
      try {
        const formData = new FormData()
        formData.append("file", file) // 'file' is the key expected by the API

        const response = await AuthService.ScanCCCD(formData)
        if (response?.Object) {
          if (onScanSuccess) {
            onScanSuccess(response.Object)
          }
        } else {
          message.error("Scan CCCD thất bại. Vui lòng thử lại.")
          console.error("Scan CCCD API error:", response)
        }
      } catch (error) {
        message.error("Có lỗi xảy ra khi quét CCCD.")
        console.error("Error calling ScanCCCD API:", error)
      }
    }
    return false // Prevent Ant Design's default upload behavior
  }

  const handleRemove = e => {
    e.stopPropagation() // Prevent re-triggering upload
    setPreviewImage(null)
    form.setFieldsValue({ [fieldName]: null })
  }

  return (
    <Upload accept="image/*" showUploadList={false} beforeUpload={beforeUpload}>
      <div className="preview-area">
        <div className="upload-box">
          {previewImage ? (
            <div className="image-preview-wrapper">
              <img
                src={previewImage}
                alt={`${label} Preview`}
                className="upload-preview"
              />
              <CloseCircleOutlined
                className="remove-icon"
                onClick={handleRemove}
              />
            </div>
          ) : (
            <div className="upload-placeholder">Click để chọn ảnh</div>
          )}
        </div>
      </div>
    </Upload>
  )
}

export default ImageUploadPreview

