import React from "react"
import RegistrationFormStep from "./RegistrationFormStep"
import MemberService from "src/services/MemberService"
import FileService from "src/services/FileService"
import { message } from "antd"

const BusinessRegistrationFlow = ({ onClose }) => {
  const handleRegistrationSubmit = async values => {
    try {
      const [cccdRes, avatarRes, portraitRes] = await Promise.all([
        FileService.uploadFile(values.CCCDImage),
        FileService.uploadFile(values.Avatar),
        FileService.uploadFile(values.Portrait),
      ])

      console.log("CCCD upload response:", cccdRes)
      console.log("Avatar upload response:", avatarRes)
      console.log("Portrait upload response:", portraitRes)

      const cccdUrl = cccdRes?.Object || ""
      const avatarUrl = avatarRes?.Object || ""
      const portraitUrl = portraitRes?.Object || ""

      if (!cccdUrl || !avatarUrl || !portraitUrl) {
        throw new Error("Upload file không trả về URL hợp lệ")
      }

      const finalData = {
        ...values,
        CCCDImage: cccdUrl,
        Avatar: avatarUrl,
        Portrait: portraitUrl,
      }

      await MemberService.RegisterOrganization(finalData)
      message.success("Đăng ký thành công!")
      onClose?.()
    } catch (error) {
      console.error("Lỗi khi đăng ký:", error)
      message.error("Có lỗi xảy ra khi đăng ký. Vui lòng thử lại.")
    }
  }

  return (
    <RegistrationFormStep
      onSubmit={handleRegistrationSubmit}
      onCancel={onClose}
    />
  )
}

export default BusinessRegistrationFlow

